// src/pages/LoginSuccess.js
import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';

function LoginSuccess() {
  const { setUser } = useUser();
  const navigate = useNavigate();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const tokenRaw = params.get("token");
    const username = params.get("username");

    if (tokenRaw && username) {
      try {
        const token = decodeURIComponent(tokenRaw);

        // Сохраняем пользователя и токен в контекст и localStorage
        setUser({ username }, token);

        // Перенаправляем после короткой задержки
        setTimeout(() => {
          navigate('/', { replace: true });
        }, 100);
      } catch (err) {
        console.error("Error decoding token:", tokenRaw, err);
      }
    }
  }, [navigate, setUser]);

  return (
    <div className="d-flex vh-100 justify-content-center align-items-center">
      <div>Logging you in...</div>
    </div>
  );
}

export default LoginSuccess;
